"use strict";parserFactory.register("semprot.com",()=>new SemprotParser);class SemprotParser extends Parser{constructor(){super()}async getChapterUrls(e){SemprotParser.author=this.findContent(e).querySelector("article.message").getAttribute("data-Author");let t=e.baseURI,r=[this.makeChapter(t,"1")],a=this.lastThreadPageNum(e);for(let e=2;e<=a;++e)r.push(this.makeChapter(t,e));return r}lastThreadPageNum(e){let t=[...e.querySelectorAll("li.pageNav-page")];return 0<t.length?parseInt(t.pop().textContent):0}makeChapter(e,t){return{sourceUrl:`${e}page-${t}`,title:`${t}`}}findContent(e){return[...e.querySelectorAll("div.block-container")].filter(e=>e.querySelector("article")).pop()}extractTitleImpl(e){return e.querySelector(".p-title-value")}extractAuthor(e){let t=SemprotParser.author;return null==t?super.extractAuthor(e):t}preprocessRawDom(e){let t=[...e.querySelectorAll("article.message")];for(let e of t)if(e.getAttribute("data-author")!==SemprotParser.author)e.remove();else{let t=e.querySelector("article.message-body");util.removeChildElementsMatchingSelector(t,".bbCodeBlock-expandLink, .semprotnenenmontok_sq"),util.resolveLazyLoadedImages(t,"img"),e.replaceWith(t)}}}